import{_ as e,o as t,c as a,b0 as r}from"./chunks/framework.BXzs9J6S.js";const m=JSON.parse('{"title":"桌面应用开发教程系列","description":"","frontmatter":{},"headers":[],"relativePath":"web开发/桌面开发/electron/index.md","filePath":"web开发/桌面开发/electron/index.md","lastUpdated":1774330698000}'),n={name:"web开发/桌面开发/electron/index.md"};function o(l,p,i,c,d,_){return t(),a("div",null,[...p[0]||(p[0]=[r('<h1 id="桌面应用开发教程系列" tabindex="-1">桌面应用开发教程系列 <a class="header-anchor" href="#桌面应用开发教程系列" aria-label="Permalink to &quot;桌面应用开发教程系列&quot;">​</a></h1><ul><li><p><a href="./electron开发环境搭建/">electron 开发环境搭建</a></p></li><li><p><a href="./桌面摄像头/">electron 开发桌面摄像头</a></p></li></ul><p>初高中时候因为家里穷，总是想着能够快点出去挣钱，似乎只有身上有钱了，才能彻底摆脱自己那贫穷带来的深深植根于内心的自卑感，所以思想动乱，在尖子班没好好学习，甚至高三整个学年的关键时候还辍学去进厂了。</p><p>高三一年没读，在外面进厂打工的时候，是让班主任帮我高考报名的，我在快要考试的时候直接回去参加高考的，考的并不理想，只考了380多分儿，最后在班主任的推荐下，去了一所学习氛围相对不错的专科学校，那所学校也已经升本科院校了。</p><p>其实在专科大一的时候，因为虚荣心买了一台苹果11pm手机导致负债又辍学了。我都打算不读这个专科了，但是母亲知道了不办休学手续会销毁学籍的后果时，还是想办法帮我去学校办了休学手续。</p><p>在这一年，我被一个打着为我好的陌生人骗去了另一个厂，他说那个厂很好，到时候干满40天后几千块钱的推荐奖励他都不会要我的，他说得很真诚的话，我虽然半信半疑，但还是信以为真了。虽然我知到要警惕，但人在低谷的时候，能有人指个好厂去进，那也总比无路可去要好得多。最终就是推荐奖励的钱被他骗去了（当然本来也属于他），我也进了那个相对很不错的厂。</p><p>他要把推荐奖励的钱拿去，我没意见，但是他用着这种骗的方式确实是属于小人行径了。他要是直接明说奖励归他，我都没问题。当然我也看得开，骗了就骗了吧，我也没亏什么，反正那钱也属于他这个推荐人。</p><p>因为是我妈帮我垫着钱还了网贷的一万多块钱，所以我挣钱以后就如数归还给我母亲。还完钱后，就没进厂了，在外面又去做了一些其他的工作。</p><p>等到次年开学，我回来复学跟着下一届同学继续读大二。因为在进厂的业余，我靠自学看视频和文档，学会了很多编程基础的概念，回来复学的时候，对编程就有了很多基础的认识了，从以前代码是什么都看不懂，到自己手撸代码、写demo，终于算是有很多进步了。（进厂的时候，我也报了一个班学习python全栈，花了我7-8k块钱，说实话，那时候我还不知道b站的视频质量远远超过很多垃圾的培训机构，在我看b站视频学会了python的很多技术后，再来看报班这个事情时，真的就像交了智商税一样，但也不能说它对我完全没作用，它给我布置一些小任务去实践，多多少少可能也帮助我走过了那段上高速的匝道。）学会了这些计算机知识后，我开始对编程和计算机越来越感兴趣，于是打算专升本继续深入学习。</p><p>因为统招专升本只有一次升学机会，所以我没敢报985/211这类好一点的本科学校，只好保守选择双非院校先考上本科再说。最后如愿以计算机科学与技术第一名的成绩381分（总分400分）考上了目标学校。</p><p>在学校里继续巩固和拓展专业知识和学习新课程，同时桃花运也来了，我恋爱了。</p><p>在刚升学的第一个学期，大概是10月20号的时候开始谈的，一直到毕业后的7月份分手了。（本科学习阶段只有2年）</p><p>因为这场恋爱，我放弃继续考研的想法，打算跟女朋友一起出社会挣钱开始享受新生活得了。因为读书读来读去，最终也是要进入社会，把自己的专业技能应用在工作中，所以我就觉得早晚都一样。当然，现在回首过去，这也是我最错误的一个决定——人生的任何时候，都不应该放弃自我成长的机会！</p><p>2024年10月份，女朋友因为在杭州找不到专业对口工作，所以去了深圳谋生，然后我在24年12月份也辞掉了杭州的工作去广州找工作，想离她近一点，陪她在一起。她工作三个月后，辞掉了手头的工作，搬来广州和我一起住。</p><p>2025年1-4月份，我一直在写自己和女朋友的毕业论文和项目。4月份答辩完后，5月初她说不想再找运维的工作了，想转行做心理咨询，于是跟别人学习怎么做心理咨询，我支持她可以尝试下。为了有更充裕的学习时间，她回老家了。我则打算去厦门发展。在7月份的时候，因为一件学校的事情两个人产生了矛盾，感情至此开始走向终点。</p><p>谈了两年的恋爱，她就这样说分就分，当然这是每个人的选择，我没有怪她的意思，只是觉得这份感情有些遗憾。</p><p>在学校学习成绩好，以为出了社会也能顺理成章找到专业对口的理想的工作，但事实是，面试了几次都没被录用，此时，我曾经在学校的骄傲一点点被现实踩在地上摩擦，我被现实打击得越来越消极，陷入自认为怀才不遇的心态困境中。我也开始畏惧失败，不再敢面试。</p><p>工作的失意加上感情的失恋，让我一度陷入思想非常矛盾的境地。我开始怀疑自己曾经读的书有什么意义，和这份真诚用心对待的感情到底算什么？我非常矛盾！我想不明白。</p><p>可以说，2025毕业这一年多的时间，我一直在渡劫，渡那个未完成自我生命主体性确认的自己。</p><p>直到年底，我才终于逐渐想明白，工作和人嘛，都是互相筛选，不合适就换嘛，何必陷入那个非要吊死在一棵树上的思想的陷阱里，让自己这么活得悲观、不如意。放下非一件事、非一个人不可的执念，打开格局，才能匹配到真正合适的人！苦到尽头便是悟，从这段恋爱当中，我也成长了不少，照见了我内心更真实的想法，我终于清楚地知道了自己真正想要的是一个什么样的对象和一段什么样的感情。</p><p>现在我已经没有心思再去追逐爱情，我只有找到人生事业的雄心壮志。</p><p>但与此同时，我还需要放下一样东西，那就是自我感动的情怀。</p><p>比如在职场中，不要企图用自己在学校的努力来打动老板获得一份工作，而是直接展示自己对于公司的价值，因为社会运转的本质就是一场利益和价值交换的过程。如果一个人没有实际有益于公司的价值，只会了某些技术，没有实际项目，那么你曾经在其他地方再怎么努力，你的努力与这家公司也没有任何关系。所以不要用自己在学校多么努力学习来说给面试官听，而是展示自己对公司真正有价值的贡献是什么。</p><p>现在我已经不再畏惧失败，更加认清了现实，摆脱了浮躁，有了更多面对任何情况的沉稳与从容，以及深刻的自我认识和社会认识，我希望这一路坎坷的的故事，能够帮助你摆脱学生思维或者走出人生低谷。</p><p>我是一个成长励志的人，自强不息的人，我会永远坚强和积极面对一切！</p>',25)])])}const f=e(n,[["render",o]]);export{m as __pageData,f as default};
